<?php
namespace App\Services\Documents;
class DocumentOwnerResolver { public function allowedOwnerTypes(): array { return array_keys(config('document_owners',[])); } public function validateOwnerType(string $ownerType): bool { return in_array($ownerType,$this->allowedOwnerTypes(),true); } public function resolveModel(string $ownerType, int $ownerId){ $cfg=config("document_owners.$ownerType"); if(!$cfg) return null; return $cfg['model']::find($ownerId); } public function validateOwnerExists(string $ownerType, int $ownerId): bool { return (bool)$this->resolveModel($ownerType,$ownerId); } public function getOwnerLabel(string $ownerType, int $ownerId): string { $owner=$this->resolveModel($ownerType,$ownerId); if(!$owner) return '-'; $cfg=config("document_owners.$ownerType"); return $owner->{$cfg['name_column']} ?? (string)$owner->id; }}
